/**
 * Unit tests for lib/token-estimator.ts (Issue #1478)
 *
 * Content-aware token estimation. Tests the three public helpers:
 *   - estimateTokens(text, kind)
 *   - detectContentKind(toolName, sample)
 *   - extractToolOutputText(input)
 */

import { describe, it, expect } from 'vitest';
import {
  estimateTokens,
  detectContentKind,
  extractToolOutputText,
  type ContentKind,
} from '../../lib/token-estimator.js';

describe('estimateTokens', () => {
  it('returns 0 for empty/null/undefined input', () => {
    expect(estimateTokens('')).toBe(0);
    expect(estimateTokens(null)).toBe(0);
    expect(estimateTokens(undefined)).toBe(0);
  });

  it('uses char/4 for prose (and unknown fallback)', () => {
    const text = 'x'.repeat(400);
    expect(estimateTokens(text, 'prose')).toBe(100);
    expect(estimateTokens(text, 'unknown')).toBe(100);
    expect(estimateTokens(text)).toBe(100); // default kind = unknown
  });

  it('uses char/3.5 for code (denser tokenization)', () => {
    const text = 'x'.repeat(350);
    expect(estimateTokens(text, 'code')).toBe(100);
  });

  it('uses char/3.0 for json (more tokens per char)', () => {
    const text = 'x'.repeat(300);
    expect(estimateTokens(text, 'json')).toBe(100);
  });

  it('returns 0 for image content regardless of length', () => {
    const text = 'x'.repeat(100_000);
    expect(estimateTokens(text, 'image')).toBe(0);
  });

  it('differs from char/4 for non-prose kinds', () => {
    const text = 'x'.repeat(10_000);
    const prose = estimateTokens(text, 'prose');
    const code = estimateTokens(text, 'code');
    const json = estimateTokens(text, 'json');
    // Ordering: json > code > prose (JSON has more tokens per char)
    expect(json).toBeGreaterThan(code);
    expect(code).toBeGreaterThan(prose);
  });

  it('rounds up (Math.ceil) so 1 char never returns 0', () => {
    expect(estimateTokens('a', 'prose')).toBe(1);
    expect(estimateTokens('abc', 'prose')).toBe(1);
    expect(estimateTokens('abcde', 'prose')).toBe(2);
  });
});

describe('detectContentKind', () => {
  describe('image detection (highest specificity)', () => {
    it('detects data: URL images', () => {
      expect(detectContentKind('Read', 'data:image/png;base64,iVBORw0KGgo...')).toBe('image');
      expect(detectContentKind('Bash', 'data:image/jpeg;base64,/9j/4AAQSkZJ...')).toBe('image');
    });

    it('detects image type markers in JSON-wrapped responses', () => {
      const text = '{"type":"image","source":{"data":"base64data..."}}';
      expect(detectContentKind('Agent', text)).toBe('image');
    });

    it('detects raw base64 prefixes for common image formats', () => {
      expect(detectContentKind('Read', 'iVBORw0KGgoAAAANSUhEUgAA')).toBe('image'); // PNG
      expect(detectContentKind('Read', '/9j/4AAQSkZJRgABAQEASABIAAD')).toBe('image'); // JPEG
      expect(detectContentKind('Read', 'R0lGODlhAQABAIAAAAAAAP')).toBe('image'); // GIF
    });

    it('image detection wins over MCP tool-name routing', () => {
      // Hypothetical: MCP tool returning a raw base64 image payload
      expect(detectContentKind('mcp__fal__generate_image', 'data:image/png;base64,abc...')).toBe('image');
    });
  });

  describe('MCP tool routing', () => {
    it('classifies MCP tool output as json', () => {
      expect(detectContentKind('mcp__context7__query-docs', '{"result": "text"}')).toBe('json');
      expect(detectContentKind('mcp__memory__search_nodes', '[{"id": 1}]')).toBe('json');
    });
  });

  describe('Read/Grep/Glob → code', () => {
    it('Read output is code', () => {
      expect(detectContentKind('Read', 'function foo() { return bar; }')).toBe('code');
    });
    it('Grep output is code', () => {
      expect(detectContentKind('Grep', 'src/foo.ts:12:  const x = 1;')).toBe('code');
    });
    it('Glob output is code', () => {
      expect(detectContentKind('Glob', 'src/foo.ts\nsrc/bar.ts')).toBe('code');
    });
  });

  describe('structural JSON detection (no tool-name hint)', () => {
    it('detects JSON objects', () => {
      expect(detectContentKind(undefined, '{"key": "value"}')).toBe('json');
    });
    it('detects JSON arrays', () => {
      expect(detectContentKind(undefined, '[1, 2, 3]')).toBe('json');
    });
    it('leading whitespace is fine', () => {
      expect(detectContentKind(undefined, '   \n{"key": "value"}')).toBe('json');
    });
  });

  describe('prose fallback', () => {
    it('Bash output is prose', () => {
      expect(detectContentKind('Bash', 'Hello, world!\nAll done.')).toBe('prose');
    });
    it('Agent narrative is prose', () => {
      expect(detectContentKind('Agent', 'I have finished the task. The result is ...')).toBe('prose');
    });
    it('unknown tool + plain text is prose', () => {
      expect(detectContentKind('NotATool', 'Just some text here')).toBe('prose');
    });
  });

  describe('empty/unknown input', () => {
    it('empty string → unknown', () => {
      expect(detectContentKind('Read', '')).toBe('unknown');
      expect(detectContentKind(undefined, null)).toBe('unknown');
    });
  });
});

describe('extractToolOutputText', () => {
  it('prefers tool_result when it is a string', () => {
    expect(extractToolOutputText({ tool_result: 'hello' })).toBe('hello');
  });

  it('extracts content from tool_result object', () => {
    expect(
      extractToolOutputText({ tool_result: { content: 'body', is_error: false } }),
    ).toBe('body');
  });

  it('falls back to output string', () => {
    expect(extractToolOutputText({ output: 'out' })).toBe('out');
  });

  it('JSON-stringifies arbitrary tool_output', () => {
    expect(extractToolOutputText({ tool_output: { a: 1, b: [2, 3] } })).toBe('{"a":1,"b":[2,3]}');
  });

  it('returns empty string when no source available', () => {
    expect(extractToolOutputText({})).toBe('');
  });

  it('handles circular reference in tool_output without throwing', () => {
    const obj: Record<string, unknown> = { a: 1 };
    obj.self = obj;
    expect(() => extractToolOutputText({ tool_output: obj })).not.toThrow();
    expect(extractToolOutputText({ tool_output: obj })).toBe('');
  });
});

describe('integration: detect + estimate', () => {
  it('Read on large source file estimates as code tokens', () => {
    const text = 'function x() { return 1; }\n'.repeat(100); // ~2700 chars
    const kind = detectContentKind('Read', text);
    expect(kind).toBe('code');
    const tokens = estimateTokens(text, kind);
    // code divisor = 3.5; text is ~2700 chars → ~771 tokens
    expect(tokens).toBeGreaterThan(700);
    expect(tokens).toBeLessThan(800);
  });

  it('MCP response estimates as json tokens (denser)', () => {
    const text = JSON.stringify({ data: Array(100).fill({ id: 1, name: 'x' }) });
    const kind = detectContentKind('mcp__memory__search_nodes', text);
    expect(kind).toBe('json');
    const tokens = estimateTokens(text, kind);
    // json divisor = 3.0; should be ~text.length / 3
    expect(tokens).toBeCloseTo(Math.ceil(text.length / 3), -1);
  });

  it('image payload counts 0 tokens but has known kind', () => {
    const text = 'data:image/png;base64,' + 'x'.repeat(50_000);
    const kind = detectContentKind('Read', text);
    expect(kind).toBe('image');
    expect(estimateTokens(text, kind)).toBe(0);
  });

  it('char/4 fallback (unknown kind) matches legacy behavior', () => {
    const text = 'x'.repeat(4000);
    const tokens = estimateTokens(text); // default kind = unknown
    expect(tokens).toBe(1000);
  });
});

describe('content-kind divisor table is exhaustive', () => {
  it('every ContentKind has defined behavior', () => {
    const kinds: ContentKind[] = ['prose', 'code', 'json', 'image', 'unknown'];
    for (const k of kinds) {
      expect(estimateTokens('test', k)).toBeGreaterThanOrEqual(0);
    }
  });
});

